rotations_list = [alpha, beta, gamma, delta, epsilon, zeta]
num_rotations = len(rotations_list)


def rotate_event(event, rotation):

    if rotation == alpha:
        return event

    rotated_event = np.zeros(event.shape)
    for idx in alpha.keys():
        if np.sum(event[idx]) and rotation[idx] in alpha.keys():
            rotated_event[rotation[idx]] = event[idx]

    return rotated_event
    #return np.array([event[list(rotation.keys())[list(rotation.values()).index(idx)]] if idx in rotation.values() else np.zeros(event.shape[-1]) for idx in np.ndindex(10,10)]).reshape(event.shape[-3:])


def rotate_randomly(training_data, has_reco=False):
    
    if has_reco:
        rotations = np.random.choice(rotations_list, size=len(training_data[0]))
        training_data[0] = np.asarray(list(map(rotate_event, training_data[0], rotations)))
    else:
        rotations = np.random.choice(rotations_list, size=len(training_data))
        training_data = np.asarray(list(map(rotate_event, training_data, rotations)))
    return training_data
        

def rotate_full(training_data, training_energy, has_reco=False):


    if has_reco:
        num_events = training_data[0].shape[0]
        rotated_dataset = np.append(training_data[0], np.zeros((num_events*(num_rotations-1),) + training_data[0].shape[-3:]), axis=0)
        for rot_idx, rotation in enumerate(rotations_list[1:]):
            for event_idx, event in enumerate(rotated_dataset[:num_events]):
                rotated_dataset[num_events*(rot_idx+1)+event_idx] = rotate_event(event, rotation)
        rotated_dataset = np.asarray([rotated_dataset, np.tile(training_data[1], num_rotations)])
    else:
        #num_events = training_data.shape[0]
        #rotated_dataset = np.append(training_data, np.zeros((num_events*(num_rotations-1),) + training_data.shape[-3:]), axis=0)
        #for rot_idx, rotation in enumerate(rotations_list[1:]):
        #    for event_idx, event in enumerate(rotated_dataset[:num_events]):
        #        print(f'Rotation {rot_idx+1}/{num_rotations-1}, Event {event_idx}/{num_events}\r')
        #        rotated_dataset[num_events*(rot_idx+1)+event_idx] = rotate_event(event, rotation)

        rotated_dataset = np.append(training_data, np.asarray([rotate_event(event, rotation) for rotation in rotations_list[1:] for event in training_data]), axis=0)

    training_energy = np.tile(training_energy, num_rotations)

    return rotated_dataset, training_energy